def process(name: str | None):
    if name is not None:
        print(f"Hello, {name}")
    else:
        print("Anonymous")

examples.toCode:
func process(name: String?) {
    if let unwrappedName = name {
        print("Hello, \(unwrappedName)")
    } else {
        print("Anonymous")
    }
}

